func newExec() (*simplecobra.Exec, error) {
	rootCmd := &rootCommand{
		commands: []simplecobra.Commander{
			newVersionCmd(),
			newEnvCommand(),
			newServerCommand(),
			newDeployCommand(),
			newConfigCommand(),
			newNewCommand(),
			newConvertCommand(),
			newImportCommand(),
			newListCommand(),
			newModCommands(),
			newGenCommand(),
			newReleaseCommand(),
		},
	}

	return simplecobra.New(rootCmd)
}
